parameters.jsCode:
const email = $json;
const text = `${email.subject} ${email.body}`.toLowerCase();

let categoryName = "General";
let categoryId = null;

if (
  text.includes("refund") ||
  text.includes("unhappy") ||
  text.includes("complaint") ||
  text.includes("delayed")
) {
  categoryName = "Complaint";
  categoryId = 1;
}

if (
  text.includes("setup") ||
  text.includes("error") ||
  text.includes("technical") ||
  text.includes("installation")
) {
  categoryName = "Technical Support";
  categoryId = 2;
}

if (
  text.includes("thank") ||
  text.includes("helpful") ||
  text.includes("friendly") ||
  text.includes("solved")
) {
  categoryName = "Positive Feedback";
  categoryId = 3;
}

if (
  text.includes("cancel") ||
  text.includes("legal complaint") ||
  email.risk_level === "critical"
) {
  categoryName = "Cancellation Risk";
  categoryId = 4;
}

if (
  text.includes("pricing") ||
  text.includes("enterprise") ||
  text.includes("plan")
) {
  categoryName = "Sales Inquiry";
  categoryId = 5;
}

return [
  {
    json: {
      email_id: email.email_id,
      category_id: categoryId,
      category_name: categoryName
    }
  }
];

parameters.query:
IF NOT EXISTS (
    SELECT 1 
    FROM email_category_map
    WHERE email_id = {{$json.email_id}}
      AND category_id = {{$json.category_id}}
)
BEGIN
    INSERT INTO email_category_map (
        email_id,
        category_id
    )
    VALUES (
        {{$json.email_id}},
        {{$json.category_id}}
    );
END;

INSERT INTO workflow_logs (
    workflow_name,
    email_id,
    execution_status,
    log_message
)
VALUES (
    '04 - Category Classification',
    {{$json.email_id}},
    'success',
    'Category classification completed by n8n workflow.'
);
